import anthropic
import sqlite3
from typing import Any

client = anthropic.Anthropic()

DB_PATH = "sales.db"

TOOLS = [
    {
        "name": "list_tables",
        "description": (
            "List all tables available in the database. "
            "Always call this first before any other tool."
        ),
        "input_schema": {"type": "object", "properties": {}, "required": []},
    },
    {
        "name": "describe_table",
        "description": (
            "Return the column names and data types for a specific table. "
            "Call this for each table that seems relevant to the question, "
            "after calling list_tables."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "table_name": {
                    "type": "string",
                    "description": "Exact name of the table to describe.",
                }
            },
            "required": ["table_name"],
        },
    },
    {
        "name": "execute_query",
        "description": (
            "Execute a read-only SELECT query. Only call this after inspecting the "
            "schema with list_tables and describe_table. Never use INSERT, UPDATE, "
            "DELETE, or any DDL statement."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "sql": {
                    "type": "string",
                    "description": "The SELECT statement to run.",
                },
                "limit": {
                    "type": "integer",
                    "description": "Maximum rows to return. Default 50, max 500.",
                },
            },
            "required": ["sql"],
        },
    },
]


def dispatch_tool(name: str, input_: dict[str, Any]) -> str:
    conn = sqlite3.connect(f"file:{DB_PATH}?mode=ro", uri=True)
    conn.row_factory = sqlite3.Row
    try:
        if name == "list_tables":
            cur = conn.execute(
                "SELECT name FROM sqlite_master WHERE type='table' ORDER BY name"
            )
            return "Tables: " + str([r[0] for r in cur.fetchall()])

        elif name == "describe_table":
            tbl = input_["table_name"]
            cur = conn.execute(f"PRAGMA table_info('{tbl}')")
            cols = [(r["name"], r["type"]) for r in cur.fetchall()]
            if not cols:
                return f"Table '{tbl}' not found."
            return "\n".join(f"  {n}  {t}" for n, t in cols)

        elif name == "execute_query":
            sql = input_["sql"].strip()
            # Hard-reject anything that is not a SELECT
            if not sql.upper().lstrip().startswith("SELECT"):
                return "Rejected: only SELECT statements are permitted."
            limit = min(int(input_.get("limit", 50)), 500)
            # Append LIMIT only if one is not already present
            if "LIMIT" not in sql.upper():
                sql = f"{sql} LIMIT {limit}"
            cur = conn.execute(sql)
            rows = [dict(r) for r in cur.fetchall()]
            return str(rows) if rows else "Query returned 0 rows."

        return f"Unknown tool: {name}"

    except Exception as exc:
        return f"Error: {exc}"
    finally:
        conn.close()


SYSTEM = """\
You are a SQL data analyst. Follow this protocol for every question:
1. Call list_tables to see all available tables.
2. Call describe_table for each table relevant to the question.
3. Write a correct SELECT query based on the schema you have just inspected.
4. Call execute_query with that SQL.
5. Interpret the results in plain English and respond to the user.

Rules:
- Only use SELECT. Never mutate data.
- Prefer explicit column names over SELECT *.
- If the question is ambiguous, state your assumption before running the query.
- If a query errors, revise it and try once more. If it errors again, explain why.
"""


def run_sql_agent(question: str, max_turns: int = 12) -> str:
    messages: list[dict] = [{"role": "user", "content": question}]

    for turn in range(max_turns):
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=2048,
            system=SYSTEM,
            tools=TOOLS,
            messages=messages,
        )

        if response.stop_reason == "end_turn":
            texts = [b.text for b in response.content if b.type == "text"]
            return texts[0] if texts else ""

        if response.stop_reason == "tool_use":
            messages.append({"role": "assistant", "content": response.content})
            results = []
            for block in response.content:
                if block.type == "tool_use":
                    output = dispatch_tool(block.name, block.input)
                    results.append(
                        {
                            "type": "tool_result",
                            "tool_use_id": block.id,
                            "content": output,
                        }
                    )
            messages.append({"role": "user", "content": results})

    return "Agent reached max turns without a final answer."


if __name__ == "__main__":
    answer = run_sql_agent(
        "Which product category had the highest average order value last month?"
    )
    print(answer)
